// ---------------- Assignments ----------------
const SCOPE_OPTIONS: { value: TemplateScope; label: string; placeholder: string }[] = [
  { value: "global", label: "Global (site-wide)", placeholder: "site" },
  { value: "route", label: "Route", placeholder: "/blog" },
  { value: "cpt", label: "Custom Post Type", placeholder: "service" },
  { value: "taxonomy", label: "Taxonomy", placeholder: "category" },
];

function AssignmentsTab() {
  const [assignments, setAssignments] = useState<TemplateAssignment[]>([]);
  const [templates, setTemplates] = useState<ThemeTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [draft, setDraft] = useState<Partial<TemplateAssignment>>({ scope: "global", target: "site", kind: "header", priority: 0 });

  const reload = async () => {
    setLoading(true);
    const [a, t] = await Promise.all([listAssignments(), listTemplates()]);
    setAssignments(a); setTemplates(t);
    setLoading(false);
  };
  useEffect(() => { void reload(); }, []);

  const templateName = (id: string) => templates.find((t) => t.id === id)?.name || "(missing)";

  const handleAdd = async () => {
    if (!draft.template_id) { toast.error("Pick a template"); return; }
    if (!draft.scope || !draft.target || !draft.kind) { toast.error("Scope, target and kind required"); return; }
    const saved = await saveAssignment({
      template_id: draft.template_id,
      scope: draft.scope as TemplateScope,
      target: draft.target,
      kind: draft.kind as TemplateKind,
      priority: draft.priority || 0,
    });
    if (saved) { toast.success("Assigned"); setDraft({ scope: "global", target: "site", kind: "header", priority: 0 }); void reload(); }
    else toast.error("Save failed");
  };

  return (
    <div className="space-y-5 max-w-4xl">
      <Card className="p-4 space-y-3">
        <h3 className="font-medium">New assignment</h3>
        <div className="grid sm:grid-cols-5 gap-2">
          <div>
            <Label className="text-xs">Template</Label>
            <Select value={draft.template_id || ""} onValueChange={(v) => {
              const tpl = templates.find((t) => t.id === v);
              setDraft((d) => ({ ...d, template_id: v, kind: (tpl?.kind as TemplateKind) || d.kind }));
            }}>
              <SelectTrigger><SelectValue placeholder="Pick…" /></SelectTrigger>
              <SelectContent>
                {templates.map((t) => <SelectItem key={t.id} value={t.id}>{t.name} ({t.kind})</SelectItem>)}
              </SelectContent>
            </Select>
          </div>
          <div>
            <Label className="text-xs">Kind</Label>
            <Select value={draft.kind || "header"} onValueChange={(v) => setDraft((d) => ({ ...d, kind: v as TemplateKind }))}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent>
                {TEMPLATE_KINDS.map((k) => <SelectItem key={k.value} value={k.value}>{k.label}</SelectItem>)}
              </SelectContent>
            </Select>
          </div>
          <div>
            <Label className="text-xs">Scope</Label>
            <Select value={draft.scope || "global"} onValueChange={(v) => setDraft((d) => ({ ...d, scope: v as TemplateScope }))}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent>
                {SCOPE_OPTIONS.map((s) => <SelectItem key={s.value} value={s.value}>{s.label}</SelectItem>)}
              </SelectContent>
            </Select>
          </div>
          <div>
            <Label className="text-xs">Target</Label>
            <Input
              value={draft.target || ""}
              onChange={(e) => setDraft((d) => ({ ...d, target: e.target.value }))}
              placeholder={SCOPE_OPTIONS.find((s) => s.value === draft.scope)?.placeholder}
            />
          </div>
          <div>
            <Label className="text-xs">Priority</Label>
            <Input type="number" value={draft.priority || 0} onChange={(e) => setDraft((d) => ({ ...d, priority: Number(e.target.value) }))} />
          </div>
        </div>
        <div className="flex justify-end">
          <Button onClick={handleAdd}><Plus className="w-4 h-4 mr-1" /> Add assignment</Button>
        </div>
        <p className="text-xs text-muted-foreground">
          Resolution order: <code>route</code> → <code>cpt</code> → <code>taxonomy</code> → <code>global</code>. Higher priority wins inside the same scope.
        </p>
      </Card>

      <Card className="overflow-hidden">
        {loading ? (
          <p className="p-6 text-sm text-muted-foreground">Loading…</p>
        ) : assignments.length === 0 ? (
          <p className="p-8 text-sm text-muted-foreground text-center">No assignments yet. Add one above to bind a header / footer / archive template to a route or CPT.</p>
        ) : (
          <ul className="divide-y">
            {assignments.map((a) => (
              <li key={a.id} className="p-3 flex items-center gap-3 text-sm">
                <Badge variant="outline">{a.kind}</Badge>
                <span className="font-medium">{templateName(a.template_id)}</span>
                <span className="text-muted-foreground">on</span>
                <Badge variant="secondary">{a.scope}: {a.target}</Badge>
                <span className="text-xs text-muted-foreground">priority {a.priority}</span>
                <div className="flex-1" />
                <Button size="sm" variant="ghost" onClick={async () => {
                  if (!confirm("Remove this assignment?")) return;
                  await deleteAssignment(a.id);
                  toast.success("Removed");
                  void reload();
                }}>
                  <Trash2 className="w-3.5 h-3.5" />
                </Button>
              </li>
            ))}
          </ul>
        )}
      </Card>
    </div>
  );
}

// ---------------- Header & Footer Layout Templates ----------------
function GlobalLayoutsTab() {
  const [items, setItems] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [previewItem, setPreviewItem] = useState<any | null>(null);

  const reload = async () => {
    setLoading(true);
    try {
      const { data } = await supabase
        .from("elementor_templates")
        .select("*")
        .in("kind", ["header", "footer"])
        .order("kind")
        .order("title");
      setItems(data || []);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    void reload();
  }, []);

  const deleteTpl = async (id: string, name: string) => {
    if (!confirm(`Are you sure you want to delete the layout template "${name}"?`)) return;
    try {
      const { error } = await supabase.from("elementor_templates").delete().eq("id", id);
      if (error) throw error;
      toast.success("Template deleted successfully");
      void reload();
    } catch (e) {
      toast.error(e instanceof Error ? e.message : "Delete failed");
    }
  };

  const createNewLayout = async () => {
    const title = prompt("Enter a title for the new header/footer layout:");
    if (!title) return;
    const kind = prompt("Enter template kind ('header' or 'footer'):", "header");
    if (!kind || (kind !== "header" && kind !== "footer")) {
      toast.error("Invalid kind. Must be 'header' or 'footer'");
      return;
    }

    try {
      // Create empty section node for editing
      const emptyLayout = [
        {
          id: Math.random().toString(36).slice(2, 9),
          elType: "section",
          settings: { padding: { top: 20, bottom: 20, unit: "px" } },
          elements: [
            {
              id: Math.random().toString(36).slice(2, 9),
              elType: "column",
              settings: { _column_size: 100 },
              elements: []
            }
          ]
        }
      ];

      const { data, error } = await supabase
        .from("elementor_templates")
        .insert({
          title,
          slug: title.toLowerCase().replace(/[^a-z0-9]+/g, "-"),
          kind,
          data: emptyLayout,
          source: "elementor"
        })
        .select()
        .single();

      if (error) throw error;
      toast.success(`Created "${title}"`);
      void reload();
    } catch (e) {
      toast.error(e instanceof Error ? e.message : "Creation failed");
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-wrap gap-4 items-center justify-between">
        <p className="text-sm text-muted-foreground max-w-xl">
          Global Layout Templates govern the structural headers, footers, and floating layouts rendered across child websites.
        </p>
        <Button onClick={createNewLayout}>
          <Plus className="w-4 h-4 mr-1" /> New Layout
        </Button>
      </div>

      {loading ? (
        <p className="text-sm text-muted-foreground">Loading layouts…</p>
      ) : items.length === 0 ? (
        <Card className="p-8 text-center text-sm text-muted-foreground">
          No global layout templates found. Run a ZIP site import to generate default header/footer layouts.
        </Card>
      ) : (
        <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {items.map((item) => (
            <Card key={item.id} className="p-5 flex flex-col gap-3 hover:shadow-md transition">
              <div className="flex items-start justify-between gap-2">
                <div className="min-w-0">
                  <h4 className="font-semibold text-base truncate">{item.title || "Untitled Layout"}</h4>
                  <p className="text-xs text-muted-foreground truncate">Slug: {item.slug || "—"}</p>
                </div>
                <Badge variant={item.kind === "header" ? "default" : "secondary"} className="capitalize">
                  {item.kind}
                </Badge>
              </div>

              <div className="bg-muted/30 border rounded-lg p-3 text-xs text-muted-foreground space-y-1 mt-1">
                <div className="flex justify-between">
                  <span>Source:</span>
                  <span className="font-mono">{item.source || "elementor"}</span>
                </div>
                <div className="flex justify-between">
                  <span>Last Updated:</span>
                  <span>{new Date(item.updated_at || item.created_at).toLocaleDateString()}</span>
                </div>
                <div className="flex justify-between">
                  <span>Widgets Count:</span>
                  <span>{Array.isArray(item.data) ? item.data.reduce((acc: number, sec: any) => acc + (sec.elements?.reduce((acc2: number, col: any) => acc2 + (col.elements?.length || 0), 0) || 0), 0) : 0}</span>
                </div>
              </div>

              <div className="flex gap-2 mt-auto pt-3">
                <Button size="sm" variant="outline" className="flex-1" onClick={() => setPreviewItem(item)}>
                  <Eye className="w-3.5 h-3.5 mr-1" /> Preview
                </Button>
                <Button size="sm" className="flex-1" asChild>
                  <a href={`/admin/edit/${item.id}`}>
                    <Edit3 className="w-3.5 h-3.5 mr-1" /> Edit Visually
                  </a>
                </Button>
                <Button size="sm" variant="ghost" className="px-2" onClick={() => deleteTpl(item.id, item.title || "")}>
                  <Trash2 className="w-3.5 h-3.5 text-destructive" />
                </Button>
              </div>
