import { useState, useEffect } from "react";
import { supabase } from "@/lib/parent";
import { Plus, Trash2, Edit2, Save, Layers, ExternalLink } from "lucide-react";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";

interface Service {
  id: string;
  site_id: string | null;
  title: string;
  description: string;
  feature_image_url: string;
  visit_link: string;
  sort_order: number;
  is_published: boolean;
}

interface Site { id: string; name: string; }

const defaultForm: Omit<Service, "id"> = {
  site_id: null, title: "", description: "", feature_image_url: "",
  visit_link: "#", sort_order: 0, is_published: true,
};

const ServicesManager = () => {
  const [items, setItems] = useState<Service[]>([]);
  const [sites, setSites] = useState<Site[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState<Omit<Service, "id">>(defaultForm);
  const [siteFilter, setSiteFilter] = useState("all");

  const fetch_ = async () => {
    const [{ data: d }, { data: s }] = await Promise.all([
      supabase.from("services").select("*").order("sort_order"),
      supabase.from("sites").select("id, name").order("name"),
    ]);
    setItems((d as unknown as Service[]) || []);
    setSites((s as unknown as Site[]) || []);
    setLoading(false);
  };

  useEffect(() => { fetch_(); }, []);

  const filtered = siteFilter === "all" ? items : items.filter(i => i.site_id === siteFilter);
  const siteOptions = [{ id: "all", name: "All Sites" }, ...sites];

  const save = async () => {
    if (!form.title.trim()) { toast.error("Title required"); return; }
    if (editingId) {
      const { error } = await supabase.from("services").update(form as any).eq("id", editingId);
      if (error) { toast.error("Failed to update"); return; }
      toast.success("Updated");
    } else {
      const { error } = await supabase.from("services").insert(form as any);
      if (error) { toast.error("Failed to create"); return; }
      toast.success("Created");
    }
    setShowForm(false); setEditingId(null); setForm(defaultForm); fetch_();
  };

  const del = async (id: string) => {
    await supabase.from("services").delete().eq("id", id);
    toast.success("Deleted"); fetch_();
  };

  const startEdit = (s: Service) => {
    const { id, ...rest } = s;
    setForm(rest); setEditingId(id); setShowForm(true);
  };

  const getSiteName = (id: string | null) => sites.find(s => s.id === id)?.name || "Global";

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-2">
        <p className="text-sm text-muted-foreground">Manage services pages with images, descriptions, and visit links per site.</p>
        <Button variant="pearl" size="sm" onClick={() => { setShowForm(true); setEditingId(null); setForm(defaultForm); }}>
          <Plus className="w-3 h-3 mr-1" /> Add Service
        </Button>
      </div>

      {sites.length > 0 && (
        <div className="flex gap-2 flex-wrap">
          {siteOptions.map(s => (
            <button key={s.id} onClick={() => setSiteFilter(s.id)}
              className={`text-xs px-3 py-1.5 rounded-full font-medium transition-colors ${siteFilter === s.id ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground hover:text-foreground"}`}>
              {s.name}
            </button>
          ))}
        </div>
      )}

      {showForm && (
        <div className="pearl-card p-5 space-y-4">
          <h3 className="text-sm font-semibold text-foreground">{editingId ? "Edit" : "Add"} Service</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div><label className="text-xs text-muted-foreground mb-1 block">Site</label>
              <select value={form.site_id || ""} onChange={e => setForm({ ...form, site_id: e.target.value || null })} className="h-9 w-full rounded-lg border border-input bg-background px-3 text-sm">
                <option value="">No site (global)</option>
                {sites.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
              </select>
            </div>
            <div><label className="text-xs text-muted-foreground mb-1 block">Title *</label>
              <input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} className="h-9 w-full rounded-lg border border-input bg-background px-3 text-sm" /></div>
            <div className="md:col-span-2"><label className="text-xs text-muted-foreground mb-1 block">Description</label>
              <textarea value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm min-h-[60px]" /></div>
            <div><label className="text-xs text-muted-foreground mb-1 block">Feature Image URL</label>
              <input value={form.feature_image_url} onChange={e => setForm({ ...form, feature_image_url: e.target.value })} className="h-9 w-full rounded-lg border border-input bg-background px-3 text-sm" /></div>
            <div><label className="text-xs text-muted-foreground mb-1 block">Visit Link</label>
              <input value={form.visit_link} onChange={e => setForm({ ...form, visit_link: e.target.value })} className="h-9 w-full rounded-lg border border-input bg-background px-3 text-sm" /></div>
            <div><label className="text-xs text-muted-foreground mb-1 block">Sort Order</label>
              <input type="number" value={form.sort_order} onChange={e => setForm({ ...form, sort_order: Number(e.target.value) })} className="h-9 w-full rounded-lg border border-input bg-background px-3 text-sm" /></div>
            <label className="flex items-center gap-2 text-xs"><input type="checkbox" checked={form.is_published} onChange={e => setForm({ ...form, is_published: e.target.checked })} className="rounded" /> Published</label>
          </div>
          <div className="flex gap-2">
            <Button variant="pearl" size="sm" onClick={save}><Save className="w-3 h-3 mr-1" /> Save</Button>
            <Button variant="outline" size="sm" onClick={() => { setShowForm(false); setEditingId(null); }}>Cancel</Button>
          </div>
        </div>
      )}

      {loading ? <p className="text-sm text-muted-foreground text-center py-8">Loading...</p> : filtered.length === 0 ? (
        <div className="text-center py-12"><Layers className="w-10 h-10 text-muted-foreground mx-auto mb-3" /><p className="text-sm text-muted-foreground">No services yet.</p></div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filtered.map(s => (
            <div key={s.id} className="pearl-card overflow-hidden group">
              {s.feature_image_url && (
                <div className="h-36 overflow-hidden">
                  <img src={s.feature_image_url} alt={s.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform" />
                </div>
              )}
              <div className="p-4 space-y-2">
                <div className="flex items-center justify-between">
                  <h4 className="text-sm font-semibold text-foreground">{s.title}</h4>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full font-semibold ${s.is_published ? "bg-pearl-gold-muted text-primary" : "bg-muted text-muted-foreground"}`}>
                    {s.is_published ? "Live" : "Draft"}
                  </span>
                </div>
                <p className="text-xs text-muted-foreground line-clamp-2">{s.description}</p>
                <p className="text-[10px] text-muted-foreground">Site: {getSiteName(s.site_id)}</p>
                <div className="flex gap-1">
                  {s.visit_link !== "#" && <a href={s.visit_link} target="_blank" rel="noopener noreferrer"><Button variant="ghost" size="sm" className="text-xs h-7"><ExternalLink className="w-3 h-3 mr-1" /> Visit</Button></a>}
                  <Button variant="ghost" size="sm" className="text-xs h-7" onClick={() => startEdit(s)}><Edit2 className="w-3 h-3" /></Button>
                  <Button variant="ghost" size="sm" className="text-xs h-7 text-muted-foreground hover:text-destructive ml-auto" onClick={() => del(s.id)}><Trash2 className="w-3 h-3" /></Button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ServicesManager;

