import { supabase } from "@/integrations/supabase/client";

export type ImageRef = {
  url: string;
  alt: string | null;
  title: string | null;
};

export type ImageJobSummary = {
  id: string;
  status: string;
  total: number;
  processed: number;
  succeeded: number;
  failed: number;
  skipped: number;
  replacements?: number;
};

const ABSOLUTE = /^https?:\/\//i;
const WP_UPLOADS = /\/wp-content\/uploads\//i;
const IMG_RE = /<img\b[^>]*>/gi;

