];

export async function listSections(): Promise<ThemeSection[]> {
  const { data } = await db.from("theme_sections").select("*").order("category").order("name");
  return (data as ThemeSection[]) || [];
}

export async function saveSection(s: Partial<ThemeSection> & { name: string; slug: string; category: string }): Promise<ThemeSection | null> {
  const payload = {
    slug: s.slug,
    name: s.name,
    category: s.category,
    description: s.description ?? null,
    blocks: s.blocks ?? [],
    variants: s.variants ?? [],
    design_tokens: s.design_tokens ?? {},
    is_global: s.is_global ?? false,
  };
  let saved: ThemeSection | null;
  if (s.id) {
    // Snapshot previous version BEFORE updating (so we can restore later).
    const { data: prev } = await db.from("theme_sections").select("*").eq("id", s.id).maybeSingle();
    if (prev) {
      await db.from("revisions").insert({
        entity_type: "theme_section",
        entity_id: s.id,
        snapshot: {
          name: prev.name, slug: prev.slug, category: prev.category, description: prev.description,
          blocks: prev.blocks, variants: prev.variants, design_tokens: prev.design_tokens,
          is_global: prev.is_global, version: prev.version,
        },
        note: "auto",
      });
    }
    const { data } = await db.from("theme_sections").update({ ...payload, version: (prev?.version || 1) + 1 }).eq("id", s.id).select().maybeSingle();
    saved = data as ThemeSection | null;
    if (saved) void logActivity({ action: "update", entity_type: "theme_section", entity_id: saved.id, entity_label: saved.name, details: { version: saved.version } });
  } else {
    const { data } = await db.from("theme_sections").insert(payload).select().maybeSingle();
    saved = data as ThemeSection | null;
    if (saved) void logActivity({ action: "create", entity_type: "theme_section", entity_id: saved.id, entity_label: saved.name });
  }
  return saved;
}

export async function deleteSection(id: string) {
  const { data: prev } = await db.from("theme_sections").select("name").eq("id", id).maybeSingle();
  await db.from("theme_sections").delete().eq("id", id);
  void logActivity({ action: "delete", entity_type: "theme_section", entity_id: id, entity_label: prev?.name || null });
}

export type SectionRevision = {
  id: string;
  entity_id: string;
  snapshot: Partial<ThemeSection> & { version?: number };
  note: string | null;
  created_at: string;
};

export async function listSectionRevisions(sectionId: string): Promise<SectionRevision[]> {
  const { data } = await db
    .from("revisions")
    .select("id, entity_id, snapshot, note, created_at")
    .eq("entity_type", "theme_section")
    .eq("entity_id", sectionId)
    .order("created_at", { ascending: false })
    .limit(50);
  return (data as SectionRevision[]) || [];
}


export async function listTemplates(): Promise<ThemeTemplate[]> {
  const { data } = await db.from("theme_templates").select("*").order("kind").order("name");
  return (data as ThemeTemplate[]) || [];
}

export async function saveTemplate(t: Partial<ThemeTemplate> & { name: string; slug: string; kind: TemplateKind }): Promise<ThemeTemplate | null> {
  const payload = {
    slug: t.slug,
    name: t.name,
    kind: t.kind,
    description: t.description ?? null,
    blocks: t.blocks ?? [],
    is_default: t.is_default ?? false,
  };
  if (t.id) {
    const { data } = await db.from("theme_templates").update(payload).eq("id", t.id).select().maybeSingle();
    if (data) void logActivity({ action: "update", entity_type: "theme_template", entity_id: data.id, entity_label: data.name, details: { kind: data.kind } });
    return data as ThemeTemplate | null;
  }
  const { data } = await db.from("theme_templates").insert(payload).select().maybeSingle();
  if (data) void logActivity({ action: "create", entity_type: "theme_template", entity_id: data.id, entity_label: data.name, details: { kind: data.kind } });
  return data as ThemeTemplate | null;
}

export async function deleteTemplate(id: string) {
  const { data: prev } = await db.from("theme_templates").select("name").eq("id", id).maybeSingle();
  await db.from("theme_templates").delete().eq("id", id);
  void logActivity({ action: "delete", entity_type: "theme_template", entity_id: id, entity_label: prev?.name || null });
}

// Global tokens (single row)
export type ThemeTokens = {
  id?: string;
  colors: Record<string, string>;
  typography: { fontFamilyHeading?: string; fontFamilyBody?: string; baseSize?: number; scale?: number };
  spacing: Record<string, number>;
