SET search_path = public
AS $$
BEGIN
  IF (TG_OP = 'UPDATE') THEN
    INSERT INTO public.revisions (entity_type, entity_id, snapshot, author_id, note)
    VALUES (
      'cpt_entry',
      OLD.id::text,
      jsonb_build_object(
        'title', OLD.title,
        'slug', OLD.slug,
        'status', OLD.status,
        'data', OLD.data,
        'cpt_slug', OLD.cpt_slug,
        'updated_at', OLD.updated_at
      ),
      OLD.author_id,
      'auto'
    );
  END IF;
  RETURN NEW;
END;
$$;
