  SELECT ARRAY[
    COALESCE(NULLIF(split_part(split_part(_version, '-', 1), '.', 1), '')::INT, 0),
    COALESCE(NULLIF(split_part(split_part(_version, '-', 1), '.', 2), '')::INT, 0),
